var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"와아~ 못 본 사이에 새 팔을 달았네, 고고학부장님?","JPN":"わあ～ちょっと見ない間に新しい腕をつけたね、考古学部長？","ENG":"Wow! I guess you got yourself a new arm there!","TWN":"哇～好久沒見，考古學教授戴上了新手臂呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다네, 리벳.","JPN":"そうだよ、リベット。","ENG":"That's right, Rivet.","TWN":"啊，是里維啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"인외의 신체에 대해서는 흥미가 있었네만, 이런 식으로 경험하게 될 줄은 몰랐어.","JPN":"人外の身体には元々興味があったが、こんな形で経験することになるとは知らなかったよ。","ENG":"I've always had an interest in nonhuman body parts, but I never expected to experience it like this.","TWN":"我對人類外的身體很感興趣，但沒想到會以這種方式體驗。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"어떤가? 기능적으로 보면, 인간의 그것보다 우수하다네.","JPN":"どうかね？　機能面では人間のそれより優れているが。","ENG":"What do you think? Functionally, it surpasses that of a human's.","TWN":"怎麼樣？從功能上來說，比人類的要優秀多了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"대박~ 어울려!","JPN":"すっごく似合ってる！","ENG":"Cool! It suits you!","TWN":"天啊～很適合你！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"포위당했군요.","JPN":"囲まれました。","ENG":"We are surrounded.","TWN":"我們被包圍了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"우리의 움직임을 눈치채고, 이곳에 병력을 집중시킨 모양입니다.","JPN":"私たちの動きに気づいて、ここに兵力を集中させていたようですね。","ENG":"They must have noticed our movement patterns and focused their forces here.","TWN":"看樣子是察覺到了我們的動向，所以把兵力集中到了這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"상관없어.","JPN":"構わない。","ENG":"It doesn't matter.","TWN":"無所謂。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"여기까지 온 이상, 눈에 거슬리는 건 전부 박살 내 버리면 그만이야.","JPN":"ここまで来た以上、目障りは全部ぶっ飛ばすまでだ。","ENG":"We've come all this way. I'm just going to destroy everything in my way.","TWN":"既然都到這裡了，把看不順眼的都給滅了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"미안하지만, 자네들에게 성배를 넘겨줄 수는 없네.","JPN":"すまないが、君たちに聖杯は渡せない。","ENG":"I'm afraid you won't be taking the Holy Grail.","TWN":"抱歉，我不能把聖杯交給你們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신적 존재가 탄생하는 순간을 내 눈으로 직접 볼 수 있는 마지막 기회니까 말이야.","JPN":"神的存在が生まれる瞬間をこの目で確認できる最後の機会だからね。","ENG":"Since, this is the last chance I'll be able to witness the birth of a godly entity.","TWN":"因為這是我最後一次能親眼看到神之存在誕生的機會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신은 과연 선할까? 악할까?","JPN":"神は善なる存在か、悪か。","ENG":"Is god good or evil?","TWN":"神是善良的？還是邪惡的？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그조차 아니라면 연약한 인간의 이지를 초월한 무언가일까……!","JPN":"それとも脆く弱い人間の理知を超越した何かか……！","ENG":"Or is god an entity that transcends the intellectual capacity of puny humans...?!","TWN":"如果二者皆不是，那難道是超越脆弱人類的理智嗎……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오직 성배만이…… 그 해묵은 궁금증을 해결할 유일한 수단이란 말일세!","JPN":"聖杯こそが……この古くからの疑問に答えを提示してくれる唯一のものなのだ！","ENG":"The Holy Grail... is the only way to get the answers to those age-old questions!","TWN":"唯有聖杯……才是解決這些陳年問題的唯一手段！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"지금 이 순간에도 조금씩 세상은 멸망을 향해 다가가고 있다.","JPN":"今この瞬間にも世界は少しずつ滅亡に近づいている。","ENG":"The end of the world is slowly approaching even as we speak.","TWN":"即使是現在，世界也朝著滅亡更近一步。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L33_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"마음만 먹으면 이 세계를 박살내어 버릴 존재들이 심연 속에서 때를 기다리고 있지.","JPN":"その気になれば、この世界を粉々にしてしまう存在が深淵の中で時を待っているのだ。","ENG":"In the depths of the abyss, there are unimaginable beings that could destroy this world on a whim.","TWN":"只要下定決心，就可以將世界毀滅掉的存在，正在深淵裡伺機而動。"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그런데 우리의 신은 무엇을 하고 있지?","JPN":"それなのに私たちの神は何をしている？","ENG":"But what is \\"our\\" God doing?","TWN":"但我們的神有什麼作為呢？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……그리고 신의 대리인을 자청하며 거들먹거리던 우리 사제들은?","JPN":"……そして神の代理人を自称しながら偉ぶっていた私たち司祭は？","ENG":"And what about our arrogant priests who call themselves the messengers of God?","TWN":"……還有那些以神的代言人自居，而得意洋洋的祭司們呢？"},"stage":{"bg":"HALL","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은…… 저로 하여금, 그 남자를 연상케 하는군요.","JPN":"あなたは……まるであの男のようなことを言いますね。","ENG":"You... remind me of that man.","TWN":"你……讓我，聯想到了那個男人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주를 모욕하던 그 가증스럽고, 역겨운 변절자를……!","JPN":"主を侮辱していた、あの厚かましくうっとうしい裏切者のような……！","ENG":"That despicable, disgusting man who insulted the lord...!","TWN":"那個侮辱主的，面目可憎的叛徒……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회의 추종자, 당신의 목적은 저자의 신병이었을 겁니다. 그렇지 않나요?","JPN":"学界の取り巻き、あなたの目的は彼の身柄だったはずです。違いますか？","ENG":"Follower of the Society, your objective was to capture him, was it not?","TWN":"學會的追隨者，你的目的是帶走那個人，對吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"맞아, 수녀님! 나는 고고학부장만 레지나 앞으로 데려가면 돼!","JPN":"そうだよ、シスター！　私は考古学部長をレジーナのとこに連れて行けたらそれでいい！","ENG":"Correct, Sister! I just need to take the Dean of Archeology to Regina!","TWN":"沒錯，修女！我只要帶考古學教授到蕾佳娜前面去就行了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼 여기는 저희가 맡겠습니다, 버넷 요원.","JPN":"ではここは私たちが預かりましょう、エージェント・バーネット。","ENG":"Then we'll take care of this, Agent Burnett.","TWN":"那這裡就由我們來負責吧，伯內特。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은 잔해를 따라 먼저 성배에 다다르도록 하세요.","JPN":"あなたは残骸と共に、先に聖杯のところへ向かってください。","ENG":"So you should follow the Remains to the Holy Grail first.","TWN":"你順著殘骸先去聖杯那裡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐? 그렇지만…….","JPN":"何だと？　けど……","ENG":"What? But...","TWN":"什麼？可是……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신에게는 반드시 이루어야 할 목표가 있을 겁니다.","JPN":"あなたには成し遂げなければならない目標があるはずです。","ENG":"You have a goal to achieve no matter what.","TWN":"你肯定有必須要實現的目標。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"지금 이 자리에 당신 말고 파편을 봉인할 수 있는 사람이 있나요?","JPN":"今この場に、あなた以外に破片の封印ができる人がいますか？","ENG":"Is there anyone else who can seal the Fragment besides you here?","TWN":"現在這個地方除了你，沒有人能封印碎片了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠어. 내가 어떻게 하면 되는데?","JPN":"わかった。俺は何をすればいい？","ENG":"Fine. What do I need to do?","TWN":"知道了。我該怎麼做？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"길은 제가 열어드리도록 하겠습니다.","JPN":"道は私が切り開きます。","ENG":"I will create a path.","TWN":"我來給你開路。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은 그저 저를 믿고 앞으로…… 앞으로 나아가세요.","JPN":"あなたはただ私を信じて……前に進んでください。","ENG":"So, trust me and advance... advance forward.","TWN":"你只要相信我，然後……往前走就好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"길을 열어준다고?","JPN":"道を切り開く？","ENG":"Create a path?","TWN":"給我開路？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"믿음에 다다르는 길이 꼭 땅에만 있으리라는 법은 없으니까요.","JPN":"信心へ繋がる道は、地面だけではないのです。","ENG":"The ground isn't the only path for one to reach faith.","TWN":"通往信仰的道路不一定只有地面。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야? 책이잖아?","JPN":"なんだ、本？","ENG":"What? Books?","TWN":"嗯？這不是書嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"갑자기 어디서 이렇게 책들이 쏟아지는 거야?","JPN":"いきなりどこから本が降って来たんだ？","ENG":"Where are all these books coming from?","TWN":"怎麼突然掉下來這麼多書？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"전 성황청 비밀 서고의 사서였습니다. 이 정도는 당연해요.","JPN":"私は聖皇庁秘密書庫の司書でした。これぐらいは当然のことです。","ENG":"I was the librarian for the Holy Curia's secret library. This is hardly new.","TWN":"我是聖皇廳秘密書庫的圖書管理員，這點程度還沒什麼。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What do you...?","TWN":"你在說什麼……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"비블리오테카…….","JPN":"ビブリオテカ……","ENG":"Bibliotheca...","TWN":"圖書館……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"스테어!","JPN":"ステア！","ENG":"Stairs!","TWN":"台階！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"마, 말도 안돼!","JPN":"そ、そんな……！","ENG":"Th-that's impossible!","TWN":"太，太不可思議了！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 종이로…… 하늘에 계단을 만든 거야?","JPN":"紙で……空への階段を作った？","ENG":"Did you just... make a staircase in the sky with paper?","TWN":"竟然用紙片……在天上搭了個台階？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잔해가…… 움직이고 있어?","JPN":"残骸が……動いてる？","ENG":"The Remains is... moving?","TWN":"殘骸……在動？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"서두르세요!","JPN":"急いでください！","ENG":"Make haste!","TWN":"快點！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 상황에서는 오래 버틸 수 없을 겁니다!","JPN":"この状況では長く持ちません！","ENG":"It will not last long in a situation like this!","TWN":"這種情況下是撐不了多久的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"젠장, 알겠다고! 종이 수녀!","JPN":"くそ……わかったよ、ペーパーシスター！","ENG":"Bloody hell, all right! Paper nun!","TWN":"該死，我知道了！紙修女！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이 빚은 절대 잊지 않을 테니까!","JPN":"この借りは必ず返す！","ENG":"I owe you one!","TWN":"這份恩情我絕對不會忘記的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"녀석이 하늘로 도망친다! 서둘러!","JPN":"奴が空に逃げるぞ、急げ！","ENG":"He's going towards the sky! Quick!","TWN":"那傢伙逃到天上去了！快追！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L44_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서 내게 그런 신탁을 속삭이셨나.","JPN":"それで、私にあんな神託を授けられたのか。","ENG":"Is this why I was given that oracle?","TWN":"所以才告訴我那個神喻嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"아니, 그냥 놔두게.","JPN":"いや、ほっておけ。","ENG":"No, just leave him.","TWN":"不，不用追。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"네? 그렇지만, 로이 버넷을 이렇게 놓칠 수는 없습니다!","JPN":"えっ、ですが……ロイ・バーネットをここで逃がすわけには！","ENG":"Pardon? But we can't let Roy Burnett go like this!","TWN":"什麼？但是，不能就這麼放他走啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"괜찮아. 그분께서는 처음부터 이렇게 될 줄 알고 계신 모양이니까.","JPN":"大丈夫だ、あのお方は最初からこうなると予想していらっしゃったようだ。","ENG":"It's fine. It seems like she knew this was going to happen all along.","TWN":"沒關係，看樣子那位一開始就知道會這樣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그 분이라 하시면……?","JPN":"あのお方と言いますと……？","ENG":"She...?","TWN":"那位是……？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"우선은 저들을 제압하는데 집중하도록 하지.","JPN":"まずは彼らを制圧することに集中しよう。","ENG":"Let us first focus on taking those down.","TWN":"先集中精力對付眼前的這些。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"걱정할 것 없네. 성배의 곁에는 학회장님이 계실 테니까 말이야.","JPN":"心配するな、聖杯の傍には学会長がいらっしゃる。","ENG":"No need to fret. The President should be by the Holy Grail's side.","TWN":"沒什麼可擔心的，因為聖杯身邊有學會會長在。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"네, 넵……!","JPN":"は、はい……！","ENG":"Y-yes, sir...!","TWN":"好，好的……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"계단이 끝나가고 있어! 이쯤에서 뛰어내리라 이건가?","JPN":"階段が途切れる！　ここで飛び降りろってことか？","ENG":"The stairs are ending! Does it want me to jump here?","TWN":"樓梯快到頭了！是讓我在這個地方跳下去吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>버</color><b>넷</b>, 가…… 가<color=#ff3636>서</color>…… 가……<color=#ff3636>서</color>. <color=#ff3636>막</color>아.","JPN":"<color=#ff3636>バー</color><b>ネット</b>、行け……行<color=#ff3636>って</color>……<color=#ff3636>止</color>め……<color=#ff3636>ろ</color>。","ENG":"<color=#ff3636>Bur</color><b>nett</b>, go... go <color=#ff3636>and</color>... go... <color=#ff3636>and</color>. <color=#ff3636>St</color>op.","TWN":"<color=#ff3636>伯</color><b>內特</b>，快……快<color=#ff3636>去</color>……快……<color=#ff3636>去</color>。<color=#ff3636>阻</color>止。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"제길, 나도 알고 있다고……!","JPN":"くそ……俺もわかってるって！","ENG":"Bollocks, I know...!","TWN":"該死，我也知道……！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"간다!","JPN":"行くぞ！","ENG":"Here goes nothing!","TWN":"走了！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"칫, 일단 제대로 도착한 건가?","JPN":"ちっ……ちゃんと着いたのか？","ENG":"Tch, I guess I arrived at the right place.","TWN":"嘖，來對地方了嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"헛……!?","JPN":"はっ……！？","ENG":"Huh...?!","TWN":"呵……？！"},"stage":{"bg":"SS_ESPR_06","bgm":"THEMA_CS_ELECTRIC","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"발 밑이 순식간에 얼어 붙었잖아? 이 능력은……!","JPN":"足元が一瞬で凍りついた……この能力は……！","ENG":"My feet just froze in an instant. This ability is...!","TWN":"腳下瞬間就被凍住了？這個能力是……！"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>버</color>……<b>넷</b>?","JPN":"<color=#ff3636>バー</color>……<b>ネット</b>？","ENG":"<color=#ff3636>Bur</color>...<b>nett</b>?","TWN":"<color=#ff3636>伯</color>……<b>內特</b>？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잔해가……! 얼어붙었어.","JPN":"残骸が……！　凍っている。","ENG":"The Remains...! It's frozen.","TWN":"殘骸……！被凍住了。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다는 말은…… 이건 맥크레디의 빙결 능력인가……?","JPN":"ということは……これはマクレディーの氷結能力か……？","ENG":"This means... this must be MacCready's freezing ability...?","TWN":"就是說……這是麥克蕾蒂的冰凍能力……？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"오호, 정답이야.","JPN":"あら、正解よ。","ENG":"Oho. Bingo.","TWN":"呵呵，答對了。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"전성기 위력에 비하면 반의반도 안 나온 거지만 말이야.","JPN":"全盛期の威力に比べると2割りにも届かないけどね。","ENG":"That's less than a quarter of my powers during my prime, though.","TWN":"與全盛時的威力相比，雖然還不到四分之一。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"결국, 빌린 몸이라서 어쩔 수 없거든.","JPN":"結局借りものの体ではこれが限界ってことよ。","ENG":"This is just borrowed flesh, so I can't help it.","TWN":"不過，畢竟是借來的身體，沒辦法。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너는……?","JPN":"お前は……？","ENG":"You're...?","TWN":"你是……？"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"역시 맥크레디 가문의 워치를 되찾기 전까지는 어쩔 수 없겠어.","JPN":"やはり、マクレディー家のウォッチを取り返すまでは仕方ないね。","ENG":"I guess there's not much I can do until I get back MacCready family's Watch.","TWN":"果然，在找回麥克蕾蒂家族的能量環之前，是沒有辦法的。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"너 같은 새파란 애송이를 상대로는…… 뭐, 이 정도도 충분하겠지.","JPN":"お前のような小僧相手には……まあ、これぐらいで十分でしょう。","ENG":"And against a kid like you... Well, this should be enough.","TWN":"對付你這個小鬼……嗯，這些應該夠了吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"얘기는 들었어. 로이 버넷이라고 했나? 반가워?","JPN":"話は聞いたわ。ロイ・バーネットと言ったっけ？　よろしくね。","ENG":"I heard about you. Roy Burnett, was it? Nice to meet you.","TWN":"我聽說了。你叫羅伊對吧？很高興見到你啊？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"곧 죽겠지만.","JPN":"もうすぐ死ぬでしょうけど。","ENG":"Even though you're going to die soon.","TWN":"雖然你馬上就要死了。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"학회의 적진 한 가운데에 난데없이 맥크레디의 능력을 쓰는 꼬마가 있다는 뜻은…….","JPN":"学会の敵陣のど真ん中に、マクレディーの能力を使うガキがいるってことは……","ENG":"A little kid, in the middle of Society territory, that can use MacCready's abilities...","TWN":"學會的敵陣中央，有個莫名其妙能使用麥克蕾蒂能力的小鬼……"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"틀림없이 네가 모든 사태의 원흉이란 뜻이겠지, 안 그래?","JPN":"お前がすべての元凶ってことだな。違うか？","ENG":"That must mean that you're the one behind all this, aren't you?","TWN":"說明整個事情的元兇就是你，對吧？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"호오? 제법 눈치가 빠른데?","JPN":"ふうん、なかなか察しがいいね。","ENG":"Ho-oh? You're quick to catch on.","TWN":"呵呵？眼睛很尖啊？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 난 네가 누군지 같은 건 관심없어.","JPN":"だがな、俺はお前の正体なんか興味ない。","ENG":"But I don't care who you are.","TWN":"但我對你是誰之類的不感興趣。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 지금 좀 바쁘거든?","JPN":"俺は今忙しいんだ。","ENG":"I'm kinda busy, you see.","TWN":"我現在有點忙。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAIN_02"},{"id":"L47_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"각오해, 꼬맹이라고 봐주지는 않을 테니까.","JPN":"覚悟しろよ、ガキだからって手加減はしないぞ。","ENG":"Brace yourself. I'm not going easy on you just because you're a child.","TWN":"做好覺悟吧，我不會因為你還小就對你手下留情。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"아하핫! 뭐?","JPN":"あははっ！　何ですって？","ENG":"A hah hah! What?","TWN":"哈哈哈！什麼？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"봐주지 않겠다고? 애송이 주제에 재밌는 소리를 지껄이잖아?","JPN":"手加減しない？　小僧のくせに面白いこと言うね。","ENG":"Not going easy on me? Hilarious, coming from a kid like you.","TWN":"不會手下留情？你這個小鬼，說的話還挺有趣的嘛？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"보아하니, 그 역겨운 버넷에게 사슬 뽑는 방패도 물려받지 못한 반푼이인 모양인데.","JPN":"見たところ、あの忌々しいバーネットから鎖を抜く盾も譲り受けられなかった半端者のようだけど。","ENG":"It seems like you didn't even inherit the chain-releasing shield from that disgusting Burnett.","TWN":"看來，那個令人作嘔的伯內特連盾牌都沒有繼承給你，你也不過就是個半吊子而已。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"네가 과연 이 전력차를 뒤집을 수 있을까?","JPN":"お前にこの戦力差を翻すことができるとでも？","ENG":"Will you be able to overcome this disparity in power?","TWN":"你認為，你真的能克服我們之間的差距嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"그래도 그 자식의 손자니까 조금은 기대하고 있어.","JPN":"けれど、あいつの孫だから少しは期待しているよ。","ENG":"I have some faith in you, though. You're his grandson, after all.","TWN":"不過畢竟是那傢伙的孫子，所以我對你還有點期待。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"분발하는 게 좋을 거야. 너도 그 옆에 잔해처럼 넘쳐흐르기 싫다면 말이지.","JPN":"頑張ったほうがいいわ。あなたも隣の残骸みたいになりたくなければね。","ENG":"So give your everything, unless you want to end up like the Remains next to you.","TWN":"如果你不想和你身旁的那個殘骸一樣溢出來，那最好就振作起來。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"하핫, 이거 나도 깜짝 놀랐지 뭐야?","JPN":"あはは、私もびっくりしたのよ。","ENG":"Hah hah, I was surprised too.","TWN":"哈哈哈，這個我也嚇了一跳呢？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"원래 잔해란, 파편을 이식한 신체가 버티지 못하고 에너지가 넘쳐 흘러버린 실패작이거든.","JPN":"残骸はね、破片を移植された身体が耐えきれず、エネルギーが溢れ出てしまった失敗作なの。","ENG":"Remains are failures that are the result of Fragment-implanted bodies overflowing with energy.","TWN":"殘骸本就是移植了碎片以後，身體無法支撐下去以至於能量過剩的失敗品。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"실패작 주제에 인간의 집념이 그대로 남아있을 줄이야.","JPN":"それなのに人間の執念を失わないなんて。","ENG":"I didn't think a failure could still preserve the tenacity of the original human.","TWN":"沒想到區區失敗品，卻仍保留有人類的執念？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"너였어……?","JPN":"お前だったのか……？","ENG":"It was you...?","TWN":"原來是你……？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네가…… 네가 그 남자를 저렇게 만든 거야……?","JPN":"お前が……あの男をあんな姿にしたのか……？","ENG":"You... made him like that...?","TWN":"是你……是你把那個男人弄成了那個樣子……？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"남자였나?","JPN":"男だったっかしら？","ENG":"Was it a \\"he\\"?","TWN":"是男的嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"으음~ 그랬던 것 같기도 하고?","JPN":"ふーん……そんな気もするけど。","ENG":"Mmm... Maybe he was? Or maybe he wasn't?","TWN":"嗯～好像是那樣？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐, 이젠 기억나지 않는 걸?","JPN":"まあ、どうせもう思い出せないもの。","ENG":"Well, I can't remember anymore.","TWN":"我現在都不記得了呢？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"어차피 그래봤자 이젠 잔해일 뿐이잖아? 아무렴 어때?","JPN":"今はただの残骸に過ぎないでしょう。そんなことどうでもいいわ。","ENG":"It's a Remains now anyway, right? Who cares?","TWN":"反正現在只是塊殘骸了吧？無所謂。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"크큭……!","JPN":"くく……！","ENG":"Hah hah...!","TWN":"呵呵……！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"크하, 크하하하하하하하하하하하……!","JPN":"くはっ、くはははははははははは……！","ENG":"Hah, HAHAHAHAHAHAHAHA...!","TWN":"哈哈哈，哈哈哈哈哈哈……！"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐야? 왜 웃는 거야? 갑자기 실성이라도 했어?","JPN":"何？　急にどうしたのかしら。気でも狂ったの？","ENG":"Huh? Why are you laughing? Have you lost it all of a sudden?","TWN":"你笑什麼？你瘋了嗎？"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"……<color=#ff3636>버</color>……<b>넷</b>.","JPN":"……<color=#ff3636>バー</color>……<b>ネット</b>。","ENG":"...<color=#ff3636>Bur</color>...<b>nett</b>.","TWN":"……<color=#ff3636>伯</color>……<b>內特</b>。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>버</color><b>넷</b>, 가…… 가<color=#ff3636>서</color>…… 가<color=#ff3636>서</color>……. <color=#ff3636>막</color>아.","JPN":"<color=#ff3636>バー</color><b>ネット</b>、行け……行<color=#ff3636>って</color>……<color=#ff3636>止</color>め……<color=#ff3636>ろ</color>。","ENG":"<color=#ff3636>Bur</color><b>nett</b>, go... go <color=#ff3636>and</color>... go... <color=#ff3636>and</color>... <color=#ff3636>St</color>op.","TWN":"<color=#ff3636>伯</color><b>內特</b>，快……快<color=#ff3636>去</color>……快<color=#ff3636>去</color>……<color=#ff3636>阻</color>止。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 됐네.","JPN":"ちょうど良かった。","ENG":"Good.","TWN":"正好。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나도 널 찾고 있었거든.","JPN":"俺もお前を探していたんだ。","ENG":"I was looking for you.","TWN":"我也在找你。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그 사람을…… 그렇게 만든 개자식을 말이야.","JPN":"あの人を……あんな姿にしたくそったれを。","ENG":"I was looking... for the tosser who made him like that.","TWN":"把那個人……弄成這樣的混帳東西。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L4_1","type":"dialog","speaker":"ANNA_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNA_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잘 들어.","JPN":"よく聞け。","ENG":"Listen carefully.","TWN":"給我聽好了。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_CHAIN_02"},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"난 지금부터 네놈들을 파편 하나 남기지 않고 박살 내 버릴 거야.","JPN":"俺は今からお前らを、破片一つ残さずぶち壊す。","ENG":"I will destroy each and every last Fragment of you from now on.","TWN":"從現在開始我要把你們這些傢伙全部砸爛，連一塊碎片都不剩下。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 수를 써서라도 부숴버릴 테니까.","JPN":"どんな手を使ってでもぶっ壊してやる。","ENG":"I will do whatever it takes to crush all of them.","TWN":"我一定會想盡辦法把你們滅掉。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"각오하라고.","JPN":"覚悟しろよ。","ENG":"So brace yourself.","TWN":"做好覺悟吧。"},"stage":{"bg":"SS_ESPR_06","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};